					penalty := 0.0
					if baseDist > 0 {
						normDelta := delta / (baseLoad * baseDist)
						penalty = normDelta * routeDensity * 0.25
					}
					score := delta + penalty
					candidates = append(candidates, cand{idx: i, deltaCost: score, routeDensity: routeDensity, isNewSlot: false})
				}
				dispatch.Assigns[i].RemoveShip(shipID)
				dispatch.Assigns[i].StationCurrent = saved[i].station
				dispatch.Assigns[i].Cost = saved[i].cost
			}
		}
		if dispatch.AssignsLen < MAXASSIGNS {
			j := dispatch.AssignsLen
			saved[j].station = dispatch.Assigns[j].StationCurrent
			saved[j].cost = dispatch.Assigns[j].Cost
			if dispatch.Assigns[j].AddShip(shipID, ori, des) {
				dispatch.Assigns[j].GenRoute()
				newCost := dispatch.Assigns[j].Cost
				if newCost >= 0 {
					delta := newCost - saved[j].cost
					routeDensity := float64(dispatch.AssignsLen+1) / float64(MAXASSIGNS)
					penalty := 0.0
					if baseDist > 0 {
						normDelta := delta / (baseLoad * baseDist)
						penalty = normDelta * routeDensity * 0.35
					}
					score := delta + penalty
					candidates = append(candidates, cand{idx: j, deltaCost: score, routeDensity: routeDensity, isNewSlot: true})
				}
				dispatch.Assigns[j].RemoveShip(shipID)
				dispatch.Assigns[j].StationCurrent = saved[j].station
				dispatch.Assigns[j].Cost = saved[j].cost
			}
		}
		bestIdx := -1
		bestScore := bigFloat
		for _, c := range candidates {
			if c.deltaCost < bestScore {
				bestScore = c.deltaCost
				bestIdx = c.idx
			}
		}
		if bestIdx >= 0 {
			dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestIdx].GenRoute()
			if bestIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
		} else {
			fallbackIdx := -1
			fallbackMinCost := bigFloat
			for i := 0; i < dispatch.AssignsLen; i++ {
				cc := dispatch.Assigns[i].Cost
				if cc < fallbackMinCost {
					fallbackMinCost = cc
					fallbackIdx = i
				}
			}
			inserted := false
			if fallbackIdx >= 0 && dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des) {
				dispatch.Assigns[fallbackIdx].GenRoute()
				inserted = true
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				k := dispatch.AssignsLen
				dispatch.Assigns[k].AddShip(shipID, ori, des)
				dispatch.Assigns[k].GenRoute()
				dispatch.AssignsLen++
				inserted = true
			}
			if !inserted && dispatch.AssignsLen == MAXASSIGNS && fallbackIdx >= 0 {
				for retry := 0; retry < dispatch.AssignsLen; retry++ {
					if dispatch.Assigns[retry].AddShip(shipID, ori, des) {
						dispatch.Assigns[retry].GenRoute()
						break
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}

